/**
 * Section Library - Left Sidebar
 * Purpose: Display categorized section templates for adding to canvas
 * Author: generated by Amazon Q
 * Created: 2024-01-15
 */

'use client';

import React, { useState } from 'react';
import { Eye } from 'lucide-react';
import { SECTION_TEMPLATES, SECTION_CATEGORIES } from '@/lib/page-builder/section-registry';
import { SectionPreviewModal } from '@/components/section-preview/SectionPreviewModal';
import { getSectionPreviewData } from '@/lib/section-preview-data';

interface SectionLibraryProps {
  onAddSection: (templateType: string) => void;
}

export function SectionLibrary({ onAddSection }: SectionLibraryProps) {
  const [searchTerm, setSearchTerm] = useState('');
  const [expandedCategories, setExpandedCategories] = useState<string[]>([
    SECTION_CATEGORIES.HEADERS,
    SECTION_CATEGORIES.CONTENT,
  ]);
  const [previewSection, setPreviewSection] = useState<{
    type: string;
    name: string;
    description: string;
  } | null>(null);

  const toggleCategory = (category: string) => {
    setExpandedCategories(prev =>
      prev.includes(category)
        ? prev.filter(c => c !== category)
        : [...prev, category]
    );
  };

  const filteredTemplates = SECTION_TEMPLATES.filter(template =>
    template.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    template.description.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const groupedTemplates = Object.values(SECTION_CATEGORIES).reduce((acc, category) => {
    acc[category] = filteredTemplates.filter(template => template.category === category);
    return acc;
  }, {} as Record<string, typeof SECTION_TEMPLATES>);

  return (
    <div className="w-full lg:w-72 xl:w-80 bg-white dark:bg-gray-800 border-r border-gray-200 dark:border-gray-700 flex flex-col max-w-full">
      {/* Header */}
      <div className="p-4 border-b border-gray-200 dark:border-gray-700">
        <h2 className="text-lg font-semibold text-gray-900 dark:text-white mb-3">
          Section Library
        </h2>
        
        {/* Search */}
        <input
          type="text"
          placeholder="Search sections..."
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-md bg-white dark:bg-gray-700 text-gray-900 dark:text-white text-sm focus:ring-2 focus:ring-blue-500 focus:border-transparent"
        />
      </div>

      {/* Categories */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {Object.entries(groupedTemplates).map(([category, templates]) => (
          <div key={category} className="space-y-2">
            {/* Category Header */}
            <button
              onClick={() => toggleCategory(category)}
              className="flex items-center justify-between w-full text-left p-2 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors"
            >
              <span className="font-medium text-gray-900 dark:text-white text-sm">
                {category}
              </span>
              <span className={`text-gray-500 transition-transform ${
                expandedCategories.includes(category) ? 'rotate-90' : ''
              }`}>
                ▶
              </span>
            </button>

            {/* Category Templates */}
            {expandedCategories.includes(category) && (
              <div className="space-y-2 ml-2">
                {templates.map((template) => (
                  <div key={template.id} className="relative group/card">
                    <button
                      onClick={() => onAddSection(template.type)}
                      className="w-full text-left p-3 rounded-lg border border-gray-200 dark:border-gray-600 hover:border-blue-300 dark:hover:border-blue-500 hover:bg-blue-50 dark:hover:bg-blue-900/20 transition-all"
                    >
                      <div className="flex items-start space-x-3">
                        {/* Icon */}
                        <div className="text-2xl group-hover/card:scale-110 transition-transform">
                          {template.icon}
                        </div>
                        
                        {/* Content */}
                        <div className="flex-1 min-w-0">
                          <h3 className="font-medium text-gray-900 dark:text-white text-sm mb-1">
                            {template.name}
                          </h3>
                          <p className="text-xs text-gray-600 dark:text-gray-400 line-clamp-2">
                            {template.description}
                          </p>
                        </div>
                      </div>
                    </button>
                    
                    {/* Preview Button */}
                    <button
                      onClick={(e) => {
                        e.stopPropagation();
                        setPreviewSection({
                          type: template.type,
                          name: template.name,
                          description: template.description,
                        });
                      }}
                      className="absolute top-2 right-2 p-1.5 bg-white dark:bg-gray-700 border border-gray-300 dark:border-gray-600 rounded-md opacity-0 group-hover/card:opacity-100 hover:bg-blue-50 dark:hover:bg-blue-900/20 hover:border-blue-400 transition-all shadow-sm"
                      title="Preview Section"
                    >
                      <Eye className="w-3.5 h-3.5 text-gray-600 dark:text-gray-400" />
                    </button>
                  </div>
                ))}
                
                {templates.length === 0 && (
                  <p className="text-xs text-gray-500 dark:text-gray-400 italic ml-2">
                    No sections found
                  </p>
                )}
              </div>
            )}
          </div>
        ))}
      </div>

      {/* Footer */}
      <div className="p-4 border-t border-gray-200 dark:border-gray-700">
        <p className="text-xs text-gray-500 dark:text-gray-400 text-center">
          Click any section to add it to your page
        </p>
      </div>

      {/* Preview Modal */}
      {previewSection && (() => {
        const previewData = getSectionPreviewData(previewSection.type);
        const templateData = SECTION_TEMPLATES.find((t) => t.type === previewSection.type)?.defaultData;
        const fallbackData = templateData || {
          id: 'preview-fallback',
          type: previewSection.type as any,
          order: 0,
          data: {},
          style: {},
        };
        
        return (
          <SectionPreviewModal
            isOpen={true}
            sectionType={previewSection.type}
            sectionName={previewSection.name}
            sectionDescription={previewSection.description}
            sampleData={previewData || fallbackData}
            onClose={() => setPreviewSection(null)}
            onAddSection={() => {
              onAddSection(previewSection.type);
              setPreviewSection(null);
            }}
          />
        );
      })()}
    </div>
  );
}